import React, { useState, useEffect, useRef } from 'react';
import { useParams, useNavigate, Link } from 'react-router-dom';
import { useCart } from '../context/CartContext';
import { useAuth } from '../context/AuthContext';
import productService from '../services/productService';

const toPrice = (value) => {
    const parsed = Number(value);
    return Number.isFinite(parsed) ? parsed : 0;
};

export default function ProductDetail() {
    const { id } = useParams();
    const navigate = useNavigate();
    const { addItem } = useCart();
    const { isAuthenticated } = useAuth();
    const [product, setProduct] = useState(null);
    const [quantity, setQuantity] = useState(1);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);
    const [cartError, setCartError] = useState(null);
    const [cartNotice, setCartNotice] = useState('');
    const [addingToCart, setAddingToCart] = useState(false);
    const [recentlyAdded, setRecentlyAdded] = useState(false);
    const recentlyAddedTimerRef = useRef<number | null>(null);

    useEffect(() => {
        const fetchProduct = async () => {
            try {
                setLoading(true);
                setError(null);
                const res = await productService.getById(id);
                setProduct(res?.data?.data || null);
            } catch (err) {
                setError(err?.response?.data?.message || 'Product not found');
                setProduct(null);
            } finally {
                setLoading(false);
            }
        };

        fetchProduct();
    }, [id]);

    const handleAddToCart = () => {
        if (!product || addingToCart) {
            return;
        }

        setCartError(null);
        setCartNotice('');

        if (!isAuthenticated) {
            navigate('/login');
            return;
        }

        setAddingToCart(true);

        addItem(product.id, quantity, {
            id: product.id,
            name: product.name,
            brand: product.brand,
            price: toPrice(product.price),
            images: product.images,
        })
            .then(() => {
                setCartNotice(`${product.name} added to cart.`);
                setRecentlyAdded(true);
                setQuantity(1);
            })
            .catch((err) => {
                console.error('Add to cart error:', err);
                const errorMessage = err?.response?.data?.message || err?.message || 'Failed to add product to cart';
                setCartError(errorMessage);
                setRecentlyAdded(false);
            })
            .finally(() => {
                setAddingToCart(false);
                if (recentlyAddedTimerRef.current !== null) {
                    window.clearTimeout(recentlyAddedTimerRef.current);
                }
                recentlyAddedTimerRef.current = window.setTimeout(() => {
                    setRecentlyAdded(false);
                    recentlyAddedTimerRef.current = null;
                }, 1200);
            });
    };

    useEffect(() => () => {
        if (recentlyAddedTimerRef.current !== null) {
            window.clearTimeout(recentlyAddedTimerRef.current);
        }
    }, []);

    if (loading) {
        return <div className="loading-container">Loading...</div>;
    }

    if (error || !product) {
        return (
            <div className="error-container">
                <p>{error || 'Product not found'}</p>
                <Link to="/products" className="btn btn-primary">
                    Back to Products
                </Link>
            </div>
        );
    }

    const stock = Number(product?.stock || 0);
    const price = toPrice(product?.price);

    return (
        <div className="product-detail-page">
            <Link to="/products" className="back-link">
                ← Back to Products
            </Link>

            <div className="product-detail-container">
                <div className="product-images">
                    {product.images && product.images.length > 0 ? (
                        <img
                            src={product.images[0]}
                            alt={product.name}
                            className="main-image"
                        />
                    ) : (
                        <div className="no-image">No Image Available</div>
                    )}
                </div>

                <div className="product-details">
                    <div className="breadcrumb">
                        <Link to="/">Home</Link>
                        <span> / </span>
                        <Link to="/products">Products</Link>
                        <span> / </span>
                        <span>{product.name}</span>
                    </div>

                    <h1>{product.name}</h1>

                    <div className="product-meta">
                        <p className="brand">
                            <strong>Brand:</strong> {product.brand}
                        </p>
                        {product.vehicle_compatibility && (
                            <p className="compatibility">
                                <strong>Vehicle Compatibility:</strong>{' '}
                                {product.vehicle_compatibility}
                            </p>
                        )}
                    </div>

                    <div className="product-pricing">
                        <p className="price">₱{price.toFixed(2)}</p>
                        <p className={`stock ${stock > 0 ? 'in-stock' : 'out-of-stock'}`}>
                            {stock > 0 ? `${stock} in stock` : 'Out of stock'}
                        </p>
                    </div>

                    <div className="product-description">
                        <h3>Description</h3>
                        <p>{product.description}</p>
                    </div>

                    <div className="add-to-cart">
                        {cartError && (
                            <div style={{ marginBottom: '1rem', padding: '0.75rem', backgroundColor: '#fee2e2', border: '1px solid #fca5a5', borderRadius: '0.375rem', color: '#991b1b', fontSize: '0.875rem' }}>
                                {cartError}
                            </div>
                        )}
                        {cartNotice && (
                            <div className="alert alert-success" role="status" style={{ marginBottom: '1rem' }}>
                                {cartNotice}
                            </div>
                        )}
                        <div className="quantity-control">
                            <label>Quantity:</label>
                            <div className="quantity-input">
                                <button onClick={() => setQuantity(Math.max(1, quantity - 1))}>
                                    −
                                </button>
                                <input
                                    type="number"
                                    value={quantity}
                                    onChange={(e) => {
                                        const nextQuantity = Math.max(1, parseInt(e.target.value, 10) || 1);
                                        setQuantity(stock > 0 ? Math.min(stock, nextQuantity) : 1);
                                    }}
                                    min="1"
                                    max={stock}
                                />
                                <button onClick={() => setQuantity(Math.min(stock, quantity + 1))}>
                                    +
                                </button>
                            </div>
                        </div>

                        {stock > 0 ? (
                            <button
                                className="btn btn-primary btn-lg"
                                onClick={handleAddToCart}
                                disabled={addingToCart}
                            >
                                {addingToCart ? 'Adding...' : recentlyAdded ? 'Added' : 'Add to Cart'}
                            </button>
                        ) : (
                            <button className="btn btn-disabled btn-lg" disabled>
                                Out of Stock
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}